    "id": "ema-emea-h-c-004212",
    "brand": "Amgevita",
    "generic": "adalimumab",
    "ingredient": "adalimumab",
    "manufacturer": "Amgen Europe B.V.",
    "strength": "",
    "form": "",
    "route": "",
    "color": "",
    "shape": "",
