    "id": "ema-emea-h-c-000419",
    "brand": "Viread",
    "generic": "tenofovir disoproxil",
    "ingredient": "tenofovir disoproxil fumarate",
    "manufacturer": "Gilead Sciences Ireland UC",
    "strength": "",
